 1	import * as React from 'react';
 2	import { getTotalCpu, getTotalMemory } from '@odf/core/components/utils';
 3	import { getAllZone } from '@odf/core/utils';
 4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 5	import { humanizeBinaryBytes } from '@odf/shared/utils';
 6	import { TextContent, Text } from '@patternfly/react-core';
 7	import { WizardNodeState } from '../reducer';
 8	
 9	export const SelectNodesTableFooter: React.FC<SelectNodesDetailsProps> =
10	  React.memo(({ nodes }) => {
11	    const { t } = useCustomTranslation();
12	
13	    const totalCpu = getTotalCpu(nodes);
14	    const totalMemory = getTotalMemory(nodes);
15	    const zones = getAllZone(nodes);
16	
17	    return (
18	      <TextContent>
19	        <Text data-test-id="nodes-selected">
20	          {t('{{nodeCount, number}} node', {
21	            nodeCount: nodes.length,
22	            count: nodes.length,
23	          })}{' '}
24	          {t('selected ({{cpu}} CPUs and {{memory}} on ', {
25	            cpu: totalCpu,
26	            memory: humanizeBinaryBytes(totalMemory).string,
27	          })}
28	          {t('{{zoneCount, number}} zone', {
29	            zoneCount: zones.size,
30	            count: zones.size,
31	          })}
32	          {')'}
33	        </Text>
34	      </TextContent>
35	    );
36	  });
37	SelectNodesTableFooter.displayName = 'SelectNodesTableFooter';
38	
39	type SelectNodesDetailsProps = {
40	  nodes: WizardNodeState[];
41	};

